const data = $input.first().json.body;
const staticData = $getWorkflowStaticData('global');

if (!staticData.notas) staticData.notas = [];

// Modo consulta: devuelve el historico de notas almacenadas
if (data.accion === 'consultar') {
  let resultados = staticData.notas;
  if (data.curso) {
    resultados = resultados.filter(n => n.curso === data.curso);
  }
  if (data.alumno) {
    resultados = resultados.filter(n =>
      n.alumno.toLowerCase().includes(data.alumno.toLowerCase())
    );
  }
  return [{ json: { status: 'ok', total: resultados.length, resultados } }];
}

// Validar campos obligatorios
if (!data.alumno || !data.curso || data.examen === undefined ||
    data.trabajo === undefined || data.participacion === undefined) {
  return [{ json: {
    status: 'error',
    mensaje: 'Campos obligatorios: alumno, curso, examen, trabajo, participacion'
  } }];
}

// Calcular media ponderada
const pE = data.ponderacion_examen || 0.5;
const pT = data.ponderacion_trabajo || 0.3;
const pP = data.ponderacion_participacion || 0.2;
const media = (data.examen * pE) + (data.trabajo * pT) + (data.participacion * pP);
const mediaR = Math.round(media * 100) / 100;

// Escala cualitativa espanola
let calificacion;
if (media < 5) calificacion = 'Insuficiente';
else if (media < 6) calificacion = 'Suficiente';
else if (media < 7) calificacion = 'Bien';
else if (media < 9) calificacion = 'Notable';
else calificacion = 'Sobresaliente';

const registro = {
  id: staticData.notas.length + 1,
  alumno: data.alumno,
  curso: data.curso,
  examen: data.examen,
  trabajo: data.trabajo,
  participacion: data.participacion,
  media: mediaR,
  calificacion,
  fecha: new Date().toLocaleString('es-ES', { timeZone: 'Europe/Madrid' })
};

staticData.notas.push(registro);
return [{ json: { status: 'ok', ...registro } }];
